diffs.replacement:
{
  "name": "SmartCity AI Traffic Command",
  "description": "A comprehensive traffic management dashboard integrating adaptive light control, automated violation detection, and emergency vehicle priority systems.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum LightStatus {
  GREEN = 'GREEN',
  YELLOW = 'YELLOW',
  RED = 'RED',
}

export enum LaneDirection {
  NORTH = 'NORTH',
  SOUTH = 'SOUTH',
  EAST = 'EAST',
  WEST = 'WEST',
}

export interface LaneStats {
  id: LaneDirection;
  density: number; // 0-100%
  vehicleCount: number;
  status: LightStatus;
  timer: number;
  hasEmergency: boolean;
}

export interface Violation {
  id: string;
  timestamp: string;
  type: 'SPEEDING' | 'OVERTAKING' | 'PARKING' | 'RED_LIGHT' | 'LANE_CROSS';
  plate: string;
  location: string;
  severity: 'LOW' | 'MEDIUM' | 'HIGH';
  capturedImage: string;
}

export interface Vehicle {
  plate: string;
  type: string;
  owner: string;
  status: 'REGISTERED' | 'WANTED' | 'STOLEN';
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeTrafficIncidents = async (violations: any[]) => {
  try {
    const prompt = `Analyze the following traffic violations data from the last hour and suggest system optimizations or law enforcement patrol adjustments: ${JSON.stringify(violations)}`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: "You are a senior traffic management AI consultant. Provide concise, data-driven insights. Format your response in clean Markdown.",
        temperature: 0.7,
      }
    });

    return response.text;
  } catch (error) {
    console.error("AI Analysis failed:", error);
    return "Error generating AI insights. Check system logs.";
  }
};

export const getSmartTimingSuggestion = async (laneData: any) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Current lane densities: ${JSON.stringify(laneData)}. Suggest optimal green light duration for each lane to minimize congestion.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            north: { type: Type.NUMBER },
            south: { type: Type.NUMBER },
            east: { type: Type.NUMBER },
            west: { type: Type.NUMBER },
            reasoning: { type: Type.STRING }
          }
        }
      }
    });
    return JSON.parse(response.text);
  } catch (error) {
    return null;
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { 
  LayoutDashboard, 
  ShieldAlert, 
  Map as MapIcon, 
  Settings, 
  Activity, 
  Bell, 
  Car, 
  AlertCircle,
  Cpu,
  Zap
} from 'lucide-react';
import { LaneDirection, LightStatus, LaneStats, Violation } from './types';
import Dashboard from './components/Dashboard';
import ViolationFeed from './components/ViolationFeed';
import JunctionMonitor from './components/JunctionMonitor';
import AISights from './components/AISights';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'overview' | 'monitor' | 'violations' | 'ai'>('overview');
  const [lanes, setLanes] = useState<LaneStats[]>([
    { id: LaneDirection.NORTH, density: 45, vehicleCount: 12, status: LightStatus.GREEN, timer: 30, hasEmergency: false },
    { id: LaneDirection.SOUTH, density: 40, vehicleCount: 10, status: LightStatus.GREEN, timer: 30, hasEmergency: false },
    { id: LaneDirection.EAST, density: 15, vehicleCount: 4, status: LightStatus.RED, timer: 60, hasEmergency: false },
    { id: LaneDirection.WEST, density: 20, vehicleCount: 5, status: LightStatus.RED, timer: 60, hasEmergency: false },
  ]);

  const [violations, setViolations] = useState<Violation[]>([]);
  const [isEmergencyActive, setIsEmergencyActive] = useState(false);

  // Simulate real-time updates
  useEffect(() => {
    const interval = setInterval(() => {
      setLanes(prev => prev.map(lane => {
        // Decrease timer
        let nextTimer = lane.timer - 1;
        let nextStatus = lane.status;

        if (nextTimer <= 0) {
          if (lane.status === LightStatus.GREEN) {
            nextStatus = LightStatus.YELLOW;
            nextTimer = 5;
          } else if (lane.status === LightStatus.YELLOW) {
            nextStatus = LightStatus.RED;
            nextTimer = 60;
          } else {
            nextStatus = LightStatus.GREEN;
            nextTimer = 30;
          }
        }

        // Random density fluctuation
        const densityChange = Math.floor(Math.random() * 5) - 2;
        const newDensity = Math.max(0, Math.min(100, lane.density + densityChange));

        return { 
          ...lane, 
          timer: nextTimer, 
          status: nextStatus,
          density: newDensity,
          vehicleCount: Math.floor(newDensity / 5)
        };
      }));
    }, 1000);

    return () => clearInterval(interval);
  }, []);

  // Simulate random violations
  useEffect(() => {
    const violationTypes: Violation['type'][] = ['SPEEDING', 'OVERTAKING', 'PARKING', 'RED_LIGHT', 'LANE_CROSS'];
    const plates = ['ABC-1234', 'XYZ-9876', 'GHI-5555', 'KLM-0021'];

    const interval = setInterval(() => {
      if (Math.random() > 0.85) {
        const newViolation: Violation = {
          id: Math.random().toString(36).substr(2, 9),
          timestamp: new Date().toLocaleTimeString(),
          type: violationTypes[Math.floor(Math.random() * violationTypes.length)],
          plate: plates[Math.floor(Math.random() * plates.length)],
          location: 'Main Junction - Cam 04',
          severity: Math.random() > 0.7 ? 'HIGH' : (Math.random() > 0.4 ? 'MEDIUM' : 'LOW'),
          capturedImage: `https://picsum.photos/seed/${Math.random()}/300/200`
        };
        setViolations(prev => [newViolation, ...prev].slice(0, 50));
      }
    }, 5000);

    return () => clearInterval(interval);
  }, []);

  const triggerEmergency = () => {
    setIsEmergencyActive(true);
    setLanes(prev => prev.map(lane => {
      if (lane.id === LaneDirection.NORTH) {
        return { ...lane, status: LightStatus.GREEN, timer: 99, hasEmergency: true };
      }
      return { ...lane, status: LightStatus.RED, timer: 99, hasEmergency: false };
    }));

    setTimeout(() => {
      setIsEmergencyActive(false);
      setLanes(prev => prev.map(lane => ({ ...lane, hasEmergency: false, timer: 30 })));
    }, 10000);
  };

  return (
    <div className="flex h-screen bg-slate-950 text-slate-200">
      {/* Sidebar */}
      <nav className="w-20 lg:w-64 bg-slate-900 border-r border-slate-800 flex flex-col items-center lg:items-stretch p-4 gap-6">
        <div className="flex items-center gap-3 px-2 py-4 mb-4">
          <div className="bg-emerald-500/20 p-2 rounded-lg border border-emerald-500/50">
            <ShieldAlert className="w-6 h-6 text-emerald-400" />
          </div>
          <span className="text-xl font-bold hidden lg:block tracking-tight">VISION<span className="text-emerald-400">GUARD</span></span>
        </div>

        <div className="flex flex-col gap-2 w-full">
          {[
            { id: 'overview', icon: LayoutDashboard, label: 'Control Center' },
            { id: 'monitor', icon: Activity, label: 'Live Monitor' },
            { id: 'violations', icon: AlertCircle, label: 'Enforcement' },
            { id: 'ai', icon: Cpu, label: 'AI Analytics' },
          ].map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
                activeTab === tab.id 
                  ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/30' 
                  : 'text-slate-400 hover:bg-slate-800'
              }`}
            >
              <tab.icon className="w-5 h-5 shrink-0" />
              <span className="hidden lg:block font-medium">{tab.label}</span>
            </button>
          ))}
        </div>

        <div className="mt-auto flex flex-col gap-2 w-full">
          <button className="flex items-center gap-3 px-4 py-3 rounded-xl text-slate-400 hover:bg-slate-800">
            <Settings className="w-5 h-5 shrink-0" />
            <span className="hidden lg:block font-medium">Config</span>
          </button>
          <div className="p-4 bg-slate-800/50 rounded-xl hidden lg:block border border-slate-700/50">
            <div className="flex items-center justify-between mb-2">
              <span className="text-xs text-slate-400 font-semibold uppercase">System Health</span>
              <div className="w-2 h-2 rounded-full bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]"></div>
            </div>
            <div className="space-y-2">
              <div className="h-1 bg-slate-700 rounded-full overflow-hidden">
                <div className="h-full bg-emerald-500 w-[94%]"></div>
              </div>
              <p className="text-[10px] text-slate-500">Latency: 42ms | CPUs: 12%</p>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col overflow-hidden">
        {/* Header */}
        <header className="h-16 border-b border-slate-800 flex items-center justify-between px-8 bg-slate-900/50 backdrop-blur-md">
          <div className="flex items-center gap-4">
            <h1 className="text-lg font-semibold capitalize text-slate-100">{activeTab.replace('-', ' ')}</h1>
            <div className="flex items-center gap-2 bg-slate-800 px-3 py-1 rounded-full text-xs font-medium text-slate-400 border border-slate-700">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
              LIVE FEED JUNCTION 42
            </div>
          </div>

          <div className="flex items-center gap-4">
            <button 
              onClick={triggerEmergency}
              disabled={isEmergencyActive}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-bold transition-all shadow-lg ${
                isEmergencyActive 
                  ? 'bg-red-500 text-white animate-pulse cursor-not-allowed' 
                  : 'bg-orange-500/10 text-orange-400 border border-orange-500/30 hover:bg-orange-500 hover:text-white'
              }`}
            >
              <Zap className="w-4 h-4" />
              {isEmergencyActive ? 'EMERGENCY CLEARANCE ACTIVE' : 'EMERGENCY TRIGGER'}
            </button>
            <div className="relative">
              <Bell className="w-5 h-5 text-slate-400 cursor-pointer hover:text-white" />
              {violations.length > 0 && (
                <span className="absolute -top-1 -right-1 w-4 h-4 bg-emerald-500 text-slate-950 text-[10px] font-bold rounded-full flex items-center justify-center border-2 border-slate-900">
                  {violations.length}
                </span>
              )}
            </div>
          </div>
        </header>

        {/* Content View */}
        <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
          {activeTab === 'overview' && (
            <div className="grid grid-cols-1 xl:grid-cols-12 gap-6">
              <div className="xl:col-span-8 space-y-6">
                <Dashboard lanes={lanes} />
                <JunctionMonitor lanes={lanes} />
              </div>
              <div className="xl:col-span-4 h-full">
                <ViolationFeed violations={violations} />
              </div>
            </div>
          )}
          {activeTab === 'monitor' && <JunctionMonitor lanes={lanes} fullScreen />}
          {activeTab === 'violations' && <ViolationFeed violations={violations} fullWidth />}
          {activeTab === 'ai' && <AISights violations={violations} />}
        </div>
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { LaneStats, LightStatus } from '../types';
import { Car, TrafficCone, Gauge, Clock } from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer, AreaChart, Area } from 'recharts';

interface DashboardProps {
  lanes: LaneStats[];
}

const mockData = Array.from({ length: 12 }, (_, i) => ({
  time: `${i * 2}:00`,
  flow: 200 + Math.floor(Math.random() * 800),
  congestion: Math.floor(Math.random() * 100),
}));

const Dashboard: React.FC<DashboardProps> = ({ lanes }) => {
  const totalVehicles = lanes.reduce((sum, lane) => sum + lane.vehicleCount, 0);
  const avgDensity = Math.round(lanes.reduce((sum, lane) => sum + lane.density, 0) / lanes.length);

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {[
          { label: 'Active Vehicles', value: totalVehicles, icon: Car, color: 'text-emerald-400', bg: 'bg-emerald-400/10' },
          { label: 'Average Density', value: `${avgDensity}%`, icon: TrafficCone, color: 'text-blue-400', bg: 'bg-blue-400/10' },
          { label: 'Signal Uptime', value: '99.9%', icon: Gauge, color: 'text-purple-400', bg: 'bg-purple-400/10' },
          { label: 'Total Violations (1h)', value: '14', icon: Clock, color: 'text-orange-400', bg: 'bg-orange-400/10' },
        ].map((stat, i) => (
          <div key={i} className="bg-slate-900 border border-slate-800 p-5 rounded-2xl flex items-center gap-4 hover:border-slate-700 transition-colors group">
            <div className={`${stat.bg} ${stat.color} p-3 rounded-xl group-hover:scale-110 transition-transform`}>
              <stat.icon className="w-6 h-6" />
            </div>
            <div>
              <p className="text-xs text-slate-500 font-medium uppercase tracking-wider">{stat.label}</p>
              <h3 className="text-2xl font-bold text-slate-100">{stat.value}</h3>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6">
          <h3 className="text-sm font-semibold text-slate-400 mb-6 flex items-center gap-2 uppercase tracking-widest">
            <Activity className="w-4 h-4 text-emerald-400" />
            Network Throughput (VPH)
          </h3>
          <div className="h-[200px]">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={mockData}>
                <defs>
                  <linearGradient id="colorFlow" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#10b981" stopOpacity={0.3}/>
                    <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <XAxis dataKey="time" stroke="#475569" fontSize={10} tickLine={false} axisLine={false} />
                <Tooltip 
                  contentStyle={{ backgroundColor: '#0f172a', borderColor: '#1e293b', color: '#f8fafc' }}
                  itemStyle={{ color: '#10b981' }}
                />
                <Area type="monotone" dataKey="flow" stroke="#10b981" fillOpacity={1} fill="url(#colorFlow)" strokeWidth={2} />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6">
          <h3 className="text-sm font-semibold text-slate-400 mb-6 flex items-center gap-2 uppercase tracking-widest">
            <TrafficCone className="w-4 h-4 text-orange-400" />
            Congestion Heatmap
          </h3>
          <div className="h-[200px]">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={mockData}>
                <XAxis dataKey="time" stroke="#475569" fontSize={10} tickLine={false} axisLine={false} />
                <Tooltip 
                  contentStyle={{ backgroundColor: '#0f172a', borderColor: '#1e293b', color: '#f8fafc' }}
                />
                <Line type="monotone" dataKey="congestion" stroke="#f59e0b" strokeWidth={2} dot={{ fill: '#f59e0b', r: 4 }} />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React from 'react';
import { LaneStats, LightStatus, LaneDirection } from '../types';
import { Maximize2, Camera, User, Radio } from 'lucide-react';

interface JunctionMonitorProps {
  lanes: LaneStats[];
  fullScreen?: boolean;
}

const JunctionMonitor: React.FC<JunctionMonitorProps> = ({ lanes, fullScreen = false }) => {
  const getLightColor = (status: LightStatus) => {
    switch (status) {
      case LightStatus.GREEN: return 'bg-emerald-500 shadow-[0_0_15px_rgba(16,185,129,0.8)]';
      case LightStatus.YELLOW: return 'bg-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.8)]';
      case LightStatus.RED: return 'bg-rose-500 shadow-[0_0_15px_rgba(244,63,94,0.8)]';
      default: return 'bg-slate-700';
    }
  };

  return (
    <div className={`space-y-4 ${fullScreen ? 'h-full' : ''}`}>
      <div className="flex items-center justify-between">
        <h2 className="text-sm font-bold text-slate-400 flex items-center gap-2 uppercase tracking-widest">
          <Camera className="w-4 h-4 text-emerald-400" />
          Real-time Junction Visualization
        </h2>
        <div className="flex gap-2">
          <span className="flex items-center gap-1.5 px-2 py-1 bg-emerald-500/10 text-emerald-400 text-[10px] font-bold rounded border border-emerald-500/20 uppercase tracking-tighter">
            <Radio className="w-3 h-3 animate-pulse" />
            Cam: Active
          </span>
          <span className="flex items-center gap-1.5 px-2 py-1 bg-blue-500/10 text-blue-400 text-[10px] font-bold rounded border border-blue-500/20 uppercase tracking-tighter">
            FPS: 60
          </span>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        {/* Visual Map */}
        <div className="relative aspect-video bg-slate-900 rounded-2xl border border-slate-800 overflow-hidden group">
          {/* Intersection Sketch */}
          <div className="absolute inset-0 flex items-center justify-center">
            {/* Roads */}
            <div className="w-32 h-full bg-slate-800 absolute opacity-50 border-x border-slate-700"></div>
            <div className="w-full h-32 bg-slate-800 absolute opacity-50 border-y border-slate-700"></div>

            {/* Lane Indicators */}
            {lanes.map((lane) => {
              const posClasses = {
                [LaneDirection.NORTH]: 'top-4 left-1/2 -translate-x-1/2',
                [LaneDirection.SOUTH]: 'bottom-4 left-1/2 -translate-x-1/2',
                [LaneDirection.EAST]: 'right-4 top-1/2 -translate-y-1/2',
                [LaneDirection.WEST]: 'left-4 top-1/2 -translate-y-1/2',
              };

              return (
                <div key={lane.id} className={`absolute ${posClasses[lane.id]} flex flex-col items-center gap-2`}>
                  <div className="text-[10px] font-bold text-slate-500">{lane.id}</div>
                  <div className={`w-8 h-8 rounded-full ${getLightColor(lane.status)} transition-all duration-300 flex items-center justify-center`}>
                    <span className="text-[10px] font-bold text-slate-950">{lane.timer}s</span>
                  </div>
                  <div className="bg-slate-800 px-2 py-0.5 rounded text-[10px] text-slate-400 border border-slate-700">
                    {lane.density}% Full
                  </div>
                </div>
              );
            })}

            {/* Center Area */}
            <div className="w-32 h-32 border-2 border-slate-700/50 z-0"></div>
          </div>

          <div className="absolute bottom-4 left-4 right-4 flex justify-between items-center bg-slate-950/80 backdrop-blur-md p-3 rounded-xl border border-white/5 opacity-0 group-hover:opacity-100 transition-opacity">
            <div className="flex items-center gap-2">
              <Camera className="w-4 h-4 text-emerald-400" />
              <span className="text-xs font-medium">JUNCTION_042_N_MAIN</span>
            </div>
            <Maximize2 className="w-4 h-4 text-slate-400 hover:text-white cursor-pointer" />
          </div>
        </div>

        {/* Lane Status Table */}
        <div className="bg-slate-900 border border-slate-800 rounded-2xl p-4 overflow-hidden">
          <table className="w-full text-left">
            <thead>
              <tr className="text-[10px] font-bold text-slate-500 uppercase tracking-widest border-b border-slate-800">
                <th className="pb-3 px-2">Direction</th>
                <th className="pb-3 px-2">Density</th>
                <th className="pb-3 px-2">Timer</th>
                <th className="pb-3 px-2 text-right">Status</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-800">
              {lanes.map((lane) => (
                <tr key={lane.id} className="group hover:bg-slate-800/50 transition-colors">
                  <td className="py-3 px-2">
                    <div className="flex items-center gap-2">
                      <div className={`w-2 h-2 rounded-full ${lane.hasEmergency ? 'bg-rose-500 animate-ping' : 'bg-slate-700'}`}></div>
                      <span className="text-xs font-semibold">{lane.id}</span>
                    </div>
                  </td>
                  <td className="py-3 px-2">
                    <div className="flex items-center gap-3 w-32">
                      <div className="flex-1 h-1.5 bg-slate-800 rounded-full overflow-hidden">
                        <div 
                          className={`h-full rounded-full transition-all ${lane.density > 70 ? 'bg-rose-500' : (lane.density > 40 ? 'bg-amber-500' : 'bg-emerald-500')}`}
                          style={{ width: `${lane.density}%` }}
                        ></div>
                      </div>
                      <span className="text-xs text-slate-400 w-8">{lane.density}%</span>
                    </div>
                  </td>
                  <td className="py-3 px-2 font-mono text-xs font-medium text-emerald-400">{lane.timer}s</td>
                  <td className="py-3 px-2 text-right">
                    <span className={`inline-block px-2 py-0.5 rounded text-[10px] font-bold ${
                      lane.status === LightStatus.GREEN ? 'text-emerald-400 bg-emerald-400/10' :
                      lane.status === LightStatus.YELLOW ? 'text-amber-400 bg-amber-400/10' :
                      'text-rose-400 bg-rose-400/10'
                    }`}>
                      {lane.status}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default JunctionMonitor;

import React from 'react';
import { Violation } from '../types';
import { ShieldAlert, MapPin, Clock, Search, ExternalLink } from 'lucide-react';

interface ViolationFeedProps {
  violations: Violation[];
  fullWidth?: boolean;
}

const ViolationFeed: React.FC<ViolationFeedProps> = ({ violations, fullWidth = false }) => {
  const getSeverityColor = (severity: Violation['severity']) => {
    switch (severity) {
      case 'HIGH': return 'text-rose-400 bg-rose-400/10 border-rose-400/30';
      case 'MEDIUM': return 'text-amber-400 bg-amber-400/10 border-amber-400/30';
      default: return 'text-blue-400 bg-blue-400/10 border-blue-400/30';
    }
  };

  return (
    <div className={`flex flex-col h-full bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden ${fullWidth ? 'w-full' : ''}`}>
      <div className="p-4 border-b border-slate-800 flex items-center justify-between bg-slate-900/50 sticky top-0 z-10 backdrop-blur-sm">
        <h3 className="text-sm font-bold text-slate-400 flex items-center gap-2 uppercase tracking-widest">
          <ShieldAlert className="w-4 h-4 text-emerald-400" />
          Violation Enforcement Log
        </h3>
        <Search className="w-4 h-4 text-slate-500 hover:text-white cursor-pointer" />
      </div>

      <div className="flex-1 overflow-y-auto divide-y divide-slate-800 custom-scrollbar">
        {violations.length === 0 ? (
