import { GoogleGenAI, Type } from "@google/genai";

// Always initialize GoogleGenAI with the named parameter apiKey.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeTrafficIncidents = async (violations: any[]) => {
  try {
    const prompt = `Analyze the following traffic violations data from the last hour and suggest system optimizations or law enforcement patrol adjustments: ${JSON.stringify(violations)}`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: "You are a senior traffic management AI consultant. Provide concise, data-driven insights. Format your response in clean Markdown.",
        temperature: 0.7,
      }
    });

    // Extract text output directly from the .text property of the response object.
    return response.text;
  } catch (error) {
    console.error("AI Analysis failed:", error);
    return "Error generating AI insights. Check system logs.";
  }
};

export const getSmartTimingSuggestion = async (laneData: any) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Current lane densities: ${JSON.stringify(laneData)}. Suggest optimal green light duration for each lane to minimize congestion.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            north: { type: Type.NUMBER },
            south: { type: Type.NUMBER },
            east: { type: Type.NUMBER },
            west: { type: Type.NUMBER },
            reasoning: { type: Type.STRING }
          }
        }
      }
    });
    // Extract text output directly from the .text property and parse JSON.
    const text = response.text;
    return text ? JSON.parse(text.trim()) : null;
  } catch (error) {
    console.error("AI timing suggestion failed:", error);
    return null;
  }
};

