                  <td className="py-3 px-2 font-mono text-xs font-medium text-emerald-400">{lane.timer}s</td>
                  <td className="py-3 px-2 text-right">
                    <span className={`inline-block px-2 py-0.5 rounded text-[10px] font-bold ${
                      lane.status === LightStatus.GREEN ? 'text-emerald-400 bg-emerald-400/10' :
                      lane.status === LightStatus.YELLOW ? 'text-amber-400 bg-amber-400/10' :
                      'text-rose-400 bg-rose-400/10'
                    }`}>
                      {lane.status}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
      <style>{`
        @keyframes scan {
          0% { top: 0; }
          100% { top: 100%; }
        }
        .animate-scan {
          animation: scan 3s linear infinite;
          position: absolute;
          width: 100%;
        }
      `}</style>
    </div>
  );
};

export default JunctionMonitor;

import React, { useState, useEffect, useRef } from 'react';
import { LaneStats, LightStatus, LaneDirection } from '../types';
import { Maximize2, Camera, Radio, LayoutGrid, Map as MapIcon, Scan, Eye, Thermometer, ZapOff, Activity } from 'lucide-react';

interface JunctionMonitorProps {
  lanes: LaneStats[];
  fullScreen?: boolean;
}

const JunctionMonitor: React.FC<JunctionMonitorProps> = ({ lanes, fullScreen = false }) => {
  const [viewMode, setViewMode] = useState<'map' | 'cameras'>('cameras');
  const videoRef = useRef<HTMLVideoElement>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const [timestamp, setTimestamp] = useState(new Date().toISOString());
  const [streamQuality, setStreamQuality] = useState<{ fps: number, resolution: string }>({ fps: 0, resolution: 'N/A' });

  useEffect(() => {
    const timer = setInterval(() => setTimestamp(new Date().toISOString()), 1000);
    return () => clearInterval(timer);
  }, []);

  // Adaptive Stream Optimization Logic
  useEffect(() => {
    const stopStream = () => {
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
        streamRef.current = null;
      }
    };

    if (viewMode === 'cameras') {
      // Define adaptive constraints based on display context
      const constraints: MediaStreamConstraints = {
        video: {
          // Low bandwidth: reduced resolution and frame rate when not in focus/fullScreen
          width: { ideal: fullScreen ? 1920 : 640 },
          height: { ideal: fullScreen ? 1080 : 360 },
          frameRate: { ideal: fullScreen ? 30 : 10 },
          facingMode: "user" 
        }
      };

      navigator.mediaDevices.getUserMedia(constraints)
        .then(stream => {
          stopStream(); // Clean up existing stream before starting new one
          streamRef.current = stream;
          if (videoRef.current) {
            videoRef.current.srcObject = stream;
          }

          const settings = stream.getVideoTracks()[0].getSettings();
          setStreamQuality({
            fps: settings.frameRate || (fullScreen ? 30 : 10),
            resolution: `${settings.width}x${settings.height}`
          });
        })
        .catch(err => {
          console.error("Adaptive stream initialization failed:", err);
          setStreamQuality({ fps: 0, resolution: 'OFFLINE' });
        });
    } else {
      stopStream();
      setStreamQuality({ fps: 0, resolution: 'STANDBY' });
    }

    return () => stopStream();
  }, [viewMode, fullScreen]);

  const getLightColor = (status: LightStatus) => {
    switch (status) {
      case LightStatus.GREEN: return 'bg-emerald-500 shadow-[0_0_15px_rgba(16,185,129,0.8)]';
      case LightStatus.YELLOW: return 'bg-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.8)]';
      case LightStatus.RED: return 'bg-rose-500 shadow-[0_0_15px_rgba(244,63,94,0.8)]';
      default: return 'bg-slate-700';
    }
  };

  const CameraOSD = ({ id, label, effect }: { id: string, label: string, effect?: string }) => (
    <div className={`absolute inset-0 pointer-events-none z-10 p-3 flex flex-col justify-between font-mono text-[10px] ${effect}`}>
      <div className="flex justify-between items-start text-emerald-400 drop-shadow-md">
        <div className="flex flex-col gap-0.5">
          <div className="flex items-center gap-1.5 bg-slate-950/40 px-1.5 py-0.5 rounded">
            <Scan className="w-3 h-3 animate-pulse" />
            <span className="font-bold tracking-tighter">{id}</span>
          </div>
          <span className="opacity-70">{label}</span>
        </div>
        <div className="bg-slate-950/40 px-1.5 py-0.5 rounded flex items-center gap-1">
          <Radio className={`w-3 h-3 ${streamQuality.fps > 0 ? 'text-emerald-500' : 'text-slate-500'}`} />
          <span>{streamQuality.fps > 0 ? 'REC' : 'OFF'}</span>
        </div>
      </div>
      <div className="flex justify-between items-end text-emerald-400 drop-shadow-md">
        <div className="flex flex-col opacity-70">
          <span>RES: {streamQuality.resolution}</span>
          <span>FPS: {Math.round(streamQuality.fps)}</span>
        </div>
        <div className="bg-slate-950/40 px-1.5 py-0.5 rounded">
          {timestamp.split('T')[1].split('.')[0]}
        </div>
      </div>
    </div>
  );

  return (
    <div className={`space-y-4 ${fullScreen ? 'h-full flex flex-col' : ''}`}>
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-4">
          <h2 className="text-sm font-bold text-slate-400 flex items-center gap-2 uppercase tracking-widest">
            <Camera className="w-4 h-4 text-emerald-400" />
            Visual Command Center
          </h2>
          <div className="flex bg-slate-900 rounded-lg p-1 border border-slate-800">
            <button 
              onClick={() => setViewMode('cameras')}
              className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-bold transition-all ${viewMode === 'cameras' ? 'bg-emerald-500 text-slate-950 shadow-lg' : 'text-slate-400 hover:text-white'}`}
            >
              <LayoutGrid className="w-3 h-3" />
              FEEDS
            </button>
            <button 
              onClick={() => setViewMode('map')}
              className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-bold transition-all ${viewMode === 'map' ? 'bg-emerald-500 text-slate-950 shadow-lg' : 'text-slate-400 hover:text-white'}`}
            >
              <MapIcon className="w-3 h-3" />
              MAP
            </button>
          </div>
        </div>
        <div className="flex gap-2">
          <span className={`flex items-center gap-1.5 px-2 py-1 rounded border text-[10px] font-bold uppercase tracking-tighter transition-colors ${
            !fullScreen ? 'bg-amber-500/10 text-amber-400 border-amber-500/20' : 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20'
          }`}>
            {!fullScreen ? <ZapOff className="w-3 h-3" /> : <Activity className="w-3 h-3 animate-pulse" />}
            {!fullScreen ? 'LOW BANDWIDTH MODE' : 'HD PERFORMANCE MODE'}
          </span>
          <span className="flex items-center gap-1.5 px-2 py-1 bg-blue-500/10 text-blue-400 text-[10px] font-bold rounded border border-blue-500/20 uppercase tracking-tighter">
            FPS: {Math.round(streamQuality.fps)}
          </span>
        </div>
      </div>

      <div className={`grid grid-cols-1 lg:grid-cols-2 gap-4 ${fullScreen ? 'flex-1' : ''}`}>
        {/* Main Display Area */}
        <div className="relative aspect-video bg-slate-950 rounded-2xl border border-slate-800 overflow-hidden group shadow-2xl">
          {viewMode === 'map' ? (
            <div className="absolute inset-0 flex items-center justify-center bg-slate-900">
              <div className="w-32 h-full bg-slate-800 absolute opacity-50 border-x border-slate-700"></div>
              <div className="w-full h-32 bg-slate-800 absolute opacity-50 border-y border-slate-700"></div>
              {lanes.map((lane) => {
                const posClasses = {
                  [LaneDirection.NORTH]: 'top-4 left-1/2 -translate-x-1/2',
                  [LaneDirection.SOUTH]: 'bottom-4 left-1/2 -translate-x-1/2',
                  [LaneDirection.EAST]: 'right-4 top-1/2 -translate-y-1/2',
                  [LaneDirection.WEST]: 'left-4 top-1/2 -translate-y-1/2',
                };
                return (
                  <div key={lane.id} className={`absolute ${posClasses[lane.id]} flex flex-col items-center gap-2 z-20`}>
                    <div className="text-[10px] font-bold text-slate-500">{lane.id}</div>
                    <div className={`w-10 h-10 rounded-full ${getLightColor(lane.status)} transition-all duration-300 flex items-center justify-center`}>
                      <span className="text-[10px] font-bold text-slate-950">{lane.timer}s</span>
                    </div>
                  </div>
                );
              })}
              <div className="w-32 h-32 border-2 border-emerald-500/20 z-0 bg-emerald-500/5 backdrop-blur-sm"></div>
            </div>
          ) : (
            <div className="absolute inset-0 grid grid-cols-2 grid-rows-2 gap-1 bg-slate-950">
              {/* CAM 1 - Real with adaptive constraints */}
              <div className="relative bg-slate-900 border border-white/5 overflow-hidden">
                <video ref={videoRef} autoPlay playsInline muted className={`absolute inset-0 w-full h-full object-cover transition-opacity duration-700 ${streamQuality.fps > 0 ? 'opacity-80' : 'opacity-0'}`} />
                {streamQuality.fps === 0 && <div className="absolute inset-0 flex items-center justify-center text-slate-700 flex-col gap-2">
                  <Camera className="w-8 h-8 opacity-20" />
                  <span className="text-[10px] font-bold tracking-widest uppercase opacity-40">Connecting North Cam...</span>
                </div>}
                <CameraOSD id="CAM_42_N" label="NORTH_LANE_PRIMARY" />
                {!fullScreen && <div className="absolute top-2 right-2 z-20 bg-amber-500/20 p-1 rounded backdrop-blur-sm"><ZapOff className="w-3 h-3 text-amber-500" title="Low BW Mode" /></div>}
              </div>

              {/* CAM 2 - Simulated Night Vision */}
              <div className="relative bg-slate-900 border border-white/5 overflow-hidden group">
                <div className={`absolute inset-0 bg-gradient-to-b from-transparent via-emerald-500/5 to-emerald-500/10 ${!fullScreen ? 'animate-pulse-slow' : ''}`}></div>
                <div className="absolute inset-0 flex items-center justify-center">
                  <Eye className="w-12 h-12 text-emerald-500/10 animate-pulse" />
                </div>
                <div className="absolute top-1/2 left-0 right-0 h-px bg-emerald-500/20 animate-scan"></div>
                <CameraOSD id="CAM_42_S" label="SOUTH_LANE_NIGHTVISION" effect="brightness-75 contrast-125 grayscale hue-rotate-90" />
              </div>

              {/* CAM 3 - Simulated Thermal */}
              <div className="relative bg-slate-900 border border-white/5 overflow-hidden">
                <div className="absolute inset-0 bg-gradient-to-tr from-blue-900/40 via-purple-900/40 to-orange-900/40"></div>
                <div className="absolute inset-0 flex items-center justify-center">
                  <Thermometer className="w-12 h-12 text-orange-500/10" />
                </div>
                <CameraOSD id="CAM_42_E" label="EAST_THERMAL_SCAN" effect="invert-[0.2] saturate-150" />
              </div>

              {/* CAM 4 - Static Feed */}
              <div className="relative bg-slate-900 border border-white/5 overflow-hidden">
                <div className="absolute inset-0 bg-slate-900 flex items-center justify-center opacity-40">
                  <div className="w-full h-full bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-10"></div>
                </div>
                <CameraOSD id="CAM_42_W" label="WEST_LANE_RESERVE" effect="contrast-150 grayscale" />
              </div>
            </div>
          )}

          <div className="absolute bottom-4 left-4 right-4 flex justify-between items-center bg-slate-950/80 backdrop-blur-md p-3 rounded-xl border border-white/5 opacity-0 group-hover:opacity-100 transition-opacity z-20">
            <div className="flex items-center gap-2">
              <Camera className="w-4 h-4 text-emerald-400" />
              <span className="text-xs font-medium uppercase tracking-tighter">JUNCTION_042_DYNAMIC_MONITOR</span>
            </div>
            <Maximize2 className="w-4 h-4 text-slate-400 hover:text-white cursor-pointer" />
          </div>
        </div>

        {/* Lane Status Table */}
        <div className="bg-slate-900 border border-slate-800 rounded-2xl p-4 overflow-hidden shadow-xl">
          <div className="flex items-center justify-between mb-4 border-b border-slate-800 pb-2">
             <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Analytics Overlay</span>
             <div className="flex items-center gap-2">
               <span className="text-[10px] text-slate-500 uppercase">Optimization: ACTIVE</span>
               <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
             </div>
          </div>
          <table className="w-full text-left">
            <thead>
              <tr className="text-[10px] font-bold text-slate-500 uppercase tracking-widest border-b border-slate-800">
                <th className="pb-3 px-2">Direction</th>
                <th className="pb-3 px-2">Density</th>
                <th className="pb-3 px-2">Timer</th>
                <th className="pb-3 px-2 text-right">Status</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-800">
              {lanes.map((lane) => (
                <tr key={lane.id} className="group hover:bg-slate-800/50 transition-colors">
                  <td className="py-3 px-2">
                    <div className="flex items-center gap-2">
                      <div className={`w-2 h-2 rounded-full ${lane.hasEmergency ? 'bg-rose-500 animate-ping' : 'bg-slate-700'}`}></div>
                      <span className="text-xs font-semibold">{lane.id}</span>
                    </div>
                  </td>
                  <td className="py-3 px-2">
                    <div className="flex items-center gap-3 w-32">
                      <div className="flex-1 h-1.5 bg-slate-800 rounded-full overflow-hidden">
                        <div 
                          className={`h-full rounded-full transition-all ${lane.density > 70 ? 'bg-rose-500' : (lane.density > 40 ? 'bg-amber-500' : 'bg-emerald-500')}`}
                          style={{ width: `${lane.density}%` }}
                        ></div>
                      </div>
                      <span className="text-xs text-slate-400 w-8">{lane.density}%</span>
                    </div>
                  </td>
                  <td className="py-3 px-2 font-mono text-xs font-medium text-emerald-400">{lane.timer}s</td>
                  <td className="py-3 px-2 text-right">
                    <span className={`inline-block px-2 py-0.5 rounded text-[10px] font-bold ${
                      lane.status === LightStatus.GREEN ? 'text-emerald-400 bg-emerald-400/10' :
                      lane.status === LightStatus.YELLOW ? 'text-amber-400 bg-amber-400/10' :
                      'text-rose-400 bg-rose-400/10'
                    }`}>
                      {lane.status}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
      <style>{`
        @keyframes scan {
          0% { top: 0; }
          100% { top: 100%; }
        }
        .animate-scan {
          animation: scan 3s linear infinite;
          position: absolute;
          width: 100%;
        }
      `}</style>
    </div>
  );
};

export default JunctionMonitor;
